from binascii import hexlify, unhexlify
import string

from numpy import argmax

def calculate_ic(message):
    k = len(message)
    freq = {} #Create a frequency dictionary to count occurrences of each character
    for char in message:
        if char in freq:
            freq[char] += 1 #If the character is already in the frequency dictionary
        else:
            freq[char] = 1 #If the character is not already in the frequency dictionary
    sum_of_ml_values = sum(ml * (ml - 1) for ml in freq.values())
    return sum_of_ml_values / (k * (k - 1))


def friedman_test(ciphertext, alpha=0.0665, tolerance=0.01):
    r = 2
    found = False
    while not found and r < len(ciphertext):
        columns = [ciphertext[i::r] for i in range(r)]
        for col in range(r):
            ic_val = calculate_ic(columns[col])
            if abs(ic_val - alpha) < tolerance:
                found = True
                return r
        r += 1
    return None


def get_columns(ciphertext, key_length):
    return [ciphertext[i::key_length] for i in range(key_length)]

def cryptanalysis(column):
    #Real frequencies of letters in English text (A-Z)
    english_freqs = [
        0.0817, 0.0149, 0.0278, 0.0425, 0.1270, 0.0223, 0.0202, 0.0609, 0.0697,
        0.0015, 0.0077, 0.0402, 0.0241, 0.0675, 0.0751, 0.0193, 0.0010, 0.0599,
        0.0633, 0.0906, 0.0276, 0.0098, 0.0236, 0.0015, 0.0197, 0.0007
    ]
    
    best_shift = 0
    min_chi_sq = float('inf')

    #Try each shift (A=0, B=1, ..., Z=25)
    for shift in range(26):
        shifted_counts = [0] * 26
        for char in column:
            #Shift the character back by 'shift' positions
            val = (ord(char) - ord('A') - shift) % 26
            shifted_counts[val] += 1
        
        #Calculate the Chi-Squared statistic for this shift
        current_chi_sq = 0
        n = len(column)
        for i in range(26):
            expected = n * english_freqs[i]
            observed = shifted_counts[i]
            # Chi-Squared: Σ( (O - E)^2 / E )
            current_chi_sq += ((observed - expected) ** 2) / expected
            
        if current_chi_sq < min_chi_sq:
            min_chi_sq = current_chi_sq
            best_shift = shift
            
    return chr(ord('A') + best_shift)

def vigenere_decrypt(ciphertext, key):
    plaintext = []
    key_length = len(key)
    for i, char in enumerate(ciphertext):
        c = ord(char)
        k = ord(key[i % key_length]) #After maximum length of key is reached, it starts again from the beginning of the key
        
        p = (c - k) % 26 #Because for encryption we do (p + k) % 26
        
        plaintext.append(chr(p + ord('A')))
    return "".join(plaintext)

if __name__ == "__main__":
    msg = ""
    print("Friedman Test Result:The estimated key length is:")
    final_key_length = friedman_test(msg)
    print(f'Final estimated key length: {final_key_length}')
    columns = get_columns(msg, final_key_length)
    final_key_list = []
    for col in columns:
        final_key_list.append(cryptanalysis(col))
    final_key = "".join(final_key_list)
    plaintext = vigenere_decrypt(msg, final_key)
    print(plaintext)
